import{_ as a,o as t,c as s,a3 as n}from"./chunks/framework.CRbjHCyB.js";const u=JSON.parse('{"title":"Command Tree","description":"","frontmatter":{},"headers":[],"relativePath":"catter/features/command-tree.md","filePath":"en/catter/features/command-tree.md"}'),i={name:"catter/features/command-tree.md"};function o(r,e,c,d,l,p){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="command-tree" tabindex="-1">Command Tree <a class="header-anchor" href="#command-tree" aria-label="Permalink to &quot;Command Tree&quot;">​</a></h1><p>The command tree visualizes the build command DAG as an ASCII tree, showing parent-child process relationships and their commands.</p><p>Built-in script: <code>script::cmd-tree</code></p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::cmd-tree</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [options] -- </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build-command</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><code>-d, --depth &lt;n&gt;</code></td><td>Limit render depth.</td></tr><tr><td><code>-a, --args &lt;n&gt;</code></td><td>Number of arguments to show per command. Default: all.</td></tr><tr><td><code>-w, --argWidth &lt;n&gt;</code></td><td>Truncate long arguments to this width. Default: 10 characters.</td></tr></tbody></table><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><p>The output is an ANSI-colored ASCII tree using box-drawing characters (<code>│</code>, <code>├──</code>, <code>└──</code>). Colors cycle through 4 values by depth level, making it easy to distinguish nesting at a glance.</p><p>A typical build tree might look like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>make -j8</span></span>
<span class="line"><span>├── gcc -c main.c -o main.o</span></span>
<span class="line"><span>│   └── as -o main.o /tmp/ccXXXX.s</span></span>
<span class="line"><span>├── gcc -c util.c -o util.o</span></span>
<span class="line"><span>│   └── as -o util.o /tmp/ccYYYY.s</span></span>
<span class="line"><span>└── gcc main.o util.o -o app</span></span>
<span class="line"><span>    └── ld -o app main.o util.o -lc</span></span></code></pre></div><p>Each node shows the process command line, and its children are the processes it spawned. The tree is constructed from actual process interception, so it reflects exactly what happened during the build.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li><strong>Understanding build orchestration</strong> -- See how a build system spawns compilers, assemblers, and linkers.</li><li><strong>Debugging unexpected process spawning</strong> -- Identify processes you did not expect the build to invoke.</li><li><strong>Verifying capture completeness</strong> -- Confirm that all expected compilations are being intercepted by catter.</li></ul>`,14)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
